#include <stdio.h>
#include <string.h>

typedef struct {
    char name[20];
    int grade;
} Student;

int main() {
    Student students[6] = {
        {"Ahmet", 85},
        {"Ayse", 92},
        {"Mehmet", 67},
        {"Zeynep", 78},
        {"Can", 55},
        {"Elif", 88}
    };
    int count = 6;

    printf("Tum ogrenciler:\n");
    for (int i = 0; i < count; i++) {
        printf("%s: %d\n", students[i].name, students[i].grade);
    }

    // Not güncelleme
    for (int i = 0; i < count; i++) {
        if (strcmp(students[i].name, "Mehmet") == 0) {
            students[i].grade = 70;
            printf("\nMehmet'in notu guncellendi: %d\n", students[i].grade);
        }
    }

    // Geçenler / kalanlar sayısı
    int passing = 0, failing = 0;
    for (int i = 0; i < count; i++) {
        if (students[i].grade >= 60) passing++;
        else failing++;
    }

    printf("\nGecen ogrenci sayisi: %d\n", passing);
    printf("Kalan ogrenci sayisi: %d\n", failing);

    // Sıralama (basit bubble sort - en yüksekten en düşüğe)
    for (int i = 0; i < count - 1; i++) {
        for (int j = 0; j < count - i - 1; j++) {
            if (students[j].grade < students[j + 1].grade) {
                Student temp = students[j];
                students[j] = students[j + 1];
                students[j + 1] = temp;
            }
        }
    }

    printf("\nNot siralamasi (yuksekten alcaga):\n");
    for (int i = 0; i < count; i++) {
        printf("%s: %d\n", students[i].name, students[i].grade);
    }

    // Ortalama
    int total = 0;
    for (int i = 0; i < count; i++) total += students[i].grade;
    printf("\nSinif ortalamasi: %.2f\n", (double)total / count);

    return 0;
}
